      'ins-defproc-cap-p1': 'Procurement support, advanced systems integration, and PSPC compliance for defence solicitations.',
      'ins-defproc-cap-h4-2': '<a href="/technology/">Technology, Automation &amp; AI</a>',
      'ins-defproc-cap-p2': 'Enterprise data platforms and operational technology for defence operations.',
      'ins-defproc-cap-h4-3': '<a href="/logistics/">Logistics &amp; Supply Chain</a>',
